import React from "react";
import "../WelcomeMessage.css";

class WelcomeMessage extends React.Component {
  render() {
    return (
      <div className="welcome-chat-wrapper">
        <div className="welcome-chat-card">
          <div className="welcome-chat-title">
            👋 Welcome!
          </div>

          <div className="welcome-chat-body">
            Welcome to my personal page! This space is dedicated to <b>sharing my projects</b>, 
            <b>knowledge</b>, and <b>resources</b> in a way that is openly accessible to everyone. 
            The main <b>goal</b> of this page is <b>scientific outreach</b> and creating a <b>publicly 
            available repository of information</b> and <b>tools</b> related to <b>software development</b>, 
            <b>operating systems</b>, <b>programming languages</b>, and <b>technical resources</b>.
          </div>

          <div className="welcome-chat-body">
            Here you will find <b>code examples</b>, <b>guides</b>, <b>tutorials</b>, <b>repositories</b>, and <b>experiments</b> 
            designed <b>to help</b> both beginners and experienced developers <b>explore</b>, <b>learn</b>, and 
            <b>contribute</b> to the <b>shared knowledge base</b>.
            🚀 <b>Ready to dive in? Start by navigating the menu above and explore the wealth 
            of resources, projects, and learning materials available — let curiosity be your guide!</b>
          </div>
          <div className="welcome-chat-footer"/>
        </div>
      </div>
    );
  }
}

export default WelcomeMessage;
